INSERT INTO public.lessons (id, level_id, order_index, title, summary, steps) VALUES
('l1-lesson-1', 'nivel-1', 1, '¿Qué es una ración?', 'Aprende la unidad básica del conteo de carbohidratos en España.', '[{"id":"l1-1-s1","type":"explanation","title":"La unidad de trabajo","body":"En España, una ración de carbohidratos equivale a 10 gramos de HC. No es el peso del alimento, sino los carbohidratos que aporta."},{"id":"l1-1-s2","type":"example","title":"Ejemplo: pan blanco","body":"1 rebanada de pan blanco pesa 25 g, pero aporta 10 g de carbohidratos. Eso son 1,0 ración.","foodId":"pan-blanco"},{"id":"l1-1-practice","type":"practice","title":"Practica ahora","body":"Comprueba si has entendido la unidad de ración con un ejercicio rápido.","exerciseId":"n1-ex1"}]'::jsonb),
('l1-lesson-2', 'nivel-1', 2, 'Gramos y carbohidratos', 'El peso del alimento no es lo mismo que los carbohidratos.', '[{"id":"l1-2-s1","type":"explanation","title":"Dos números distintos","body":"Siempre verás dos cifras: los gramos del alimento (cuánto pesa la porción) y los gramos de carbohidratos (cuánto HC aporta). Las raciones se calculan solo con los HC."},{"id":"l1-2-s2","type":"example","title":"Ejemplo: manzana","body":"Una manzana pequeña pesa 120 g pero aporta 15 g de HC. Eso son 1,5 raciones — no 12 raciones.","foodId":"manzana"},{"id":"l1-2-practice","type":"practice","title":"Practica ahora","body":"Calcula las raciones a partir de los gramos de carbohidratos.","exerciseId":"n1-ex2"}]'::jsonb),
('l1-lesson-3', 'nivel-1', 3, 'Alimentos básicos del día a día', 'Pan, fruta y lácteos: los primeros alimentos que debes reconocer.', '[{"id":"l1-3-s1","type":"explanation","title":"Empieza por lo sencillo","body":"Antes de platos combinados, domina alimentos base: pan, frutas y lácteos. Son los que más repetirás."},{"id":"l1-3-s2","type":"example","title":"Ejemplo: leche","body":"1 taza de leche (250 ml) aporta 12 g de HC = 1,2 raciones. El yogur natural aporta menos: 5 g = 0,5 raciones.","foodId":"leche"},{"id":"l1-3-practice","type":"practice","title":"Practica ahora","body":"Identifica alimentos básicos y sus raciones.","exerciseId":"n1-ex3"}]'::jsonb),
('l2-lesson-1', 'nivel-2', 1, 'Arroz y pasta', 'Cereales cocidos: porciones habituales y raciones.', '[{"id":"l2-1-s1","type":"explanation","title":"Porciones de cereales","body":"El arroz y la pasta se miden en tazas cuando están cocidos. Una porción típica (1/3 taza) aporta unos 15 g de HC = 1,5 raciones."},{"id":"l2-1-s2","type":"example","title":"Ejemplo: arroz cocido","body":"1/3 taza de arroz (50 g) aporta 15 g de HC. Divide entre 10: 1,5 raciones.","foodId":"arroz-cocido"},{"id":"l2-1-practice","type":"practice","title":"Practica ahora","body":"Calcula raciones de cereales cocidos.","exerciseId":"n2-ex1"}]'::jsonb),
('l2-lesson-2', 'nivel-2', 2, 'Patata y boniato', 'Tubérculos en el plato diario.', '[{"id":"l2-2-s1","type":"explanation","title":"Tubérculos","body":"Patata y boniato aportan HC en porciones de media taza. El peso del tubérculo no coincide con los gramos de carbohidratos."},{"id":"l2-2-s2","type":"example","title":"Ejemplo: patata cocida","body":"1/2 taza de patata (75 g) aporta 15 g de HC = 1,5 raciones.","foodId":"patata-cocida"},{"id":"l2-2-practice","type":"practice","title":"Practica ahora","body":"Identifica tubérculos y sus raciones.","exerciseId":"n2-ex3"}]'::jsonb),
('l3-lesson-1', 'nivel-3', 1, 'Legumbres', 'Lentejas, garbanzos y alubias en porción habitual.', '[{"id":"l3-1-s1","type":"explanation","title":"Legumbres cocidas","body":"Media taza de legumbres cocidas suele aportar unos 15 g de HC. Son alimento base, aunque a veces van en platos mixtos."},{"id":"l3-1-s2","type":"example","title":"Ejemplo: lentejas","body":"1/2 taza de lentejas (100 g) = 15 g HC = 1,5 raciones.","foodId":"lentejas-cocidas"},{"id":"l3-1-practice","type":"practice","title":"Practica ahora","body":"Cuenta raciones de legumbres.","exerciseId":"n3-ex1"}]'::jsonb),
('l3-lesson-2', 'nivel-3', 2, 'Verduras con más HC', 'No todas las verduras aportan igual.', '[{"id":"l3-2-s1","type":"explanation","title":"Verduras que cuentan","body":"Zanahoria, calabaza o cebolla aportan más HC que lechuga o pepino. Hay que conocer las que sí suman raciones."},{"id":"l3-2-s2","type":"example","title":"Ejemplo: calabaza","body":"1 taza de calabaza aporta 15 g de HC = 1,5 raciones.","foodId":"calabaza"},{"id":"l3-2-practice","type":"practice","title":"Practica ahora","body":"Distingue verduras por su aporte de HC.","exerciseId":"n3-ex3"}]'::jsonb),
('l4-lesson-1', 'nivel-4', 1, '¿Qué es un plato mixto?', 'Cuando un plato combina varios ingredientes.', '[{"id":"l4-1-s1","type":"explanation","title":"Platos compuestos","body":"Un plato mixto mezcla carbohidratos, proteínas y grasas. Los HC vienen del pan, arroz, patata u otros ingredientes base."},{"id":"l4-1-s2","type":"example","title":"Ejemplo: tortilla de patata","body":"La tortilla combina huevo (modulador) y patata (HC). Una porción puede aportar unos 20 g de HC = 2,0 raciones.","foodId":"tortilla-patata"},{"id":"l4-1-practice","type":"practice","title":"Practica ahora","body":"Calcula raciones en un plato mixto.","exerciseId":"n4-ex1"}]'::jsonb),
('l4-lesson-2', 'nivel-4', 2, 'Platos españoles habituales', 'Paella, bocadillo y pizza en la vida real.', '[{"id":"l4-2-s1","type":"explanation","title":"Comida cotidiana","body":"Paella, bocadillos y pizza son platos frecuentes. Cada uno concentra HC de forma distinta según la porción."},{"id":"l4-2-s2","type":"example","title":"Ejemplo: paella","body":"1 plato de paella (300 g) puede aportar 45 g de HC = 4,5 raciones, principalmente del arroz.","foodId":"paella"},{"id":"l4-2-practice","type":"practice","title":"Practica ahora","body":"Identifica platos mixtos españoles.","exerciseId":"n4-ex3"}]'::jsonb),
('l5-lesson-1', 'nivel-5', 1, 'Combinar en una comida', 'Suma los HC de cada alimento.', '[{"id":"l5-1-s1","type":"explanation","title":"Raciones totales","body":"En un desayuno o comida real, suma los gramos de HC de cada alimento y divide entre 10 para obtener las raciones totales."},{"id":"l5-1-s2","type":"example","title":"Ejemplo: desayuno","body":"Pan (10 g HC) + leche (12 g HC) = 22 g HC total = 2,2 raciones.","foodId":"pan-blanco"},{"id":"l5-1-practice","type":"practice","title":"Practica ahora","body":"Suma raciones de una comida combinada.","exerciseId":"n5-ex1"}]'::jsonb),
('l5-lesson-2', 'nivel-5', 2, 'Moduladores: proteína sin HC', 'Pollo, pescado y huevo no aportan raciones de HC.', '[{"id":"l5-2-s1","type":"explanation","title":"Qué son los moduladores","body":"Las proteínas (pollo, carne, pescado, huevo) tienen 0 g de HC y 0 raciones. Acompañan pero no suman carbohidratos."},{"id":"l5-2-s2","type":"example","title":"Ejemplo: pollo con arroz","body":"Arroz (15 g HC) + pollo (0 g HC) = solo 1,5 raciones de HC. El pollo es modulador.","foodId":"pollo"},{"id":"l5-2-practice","type":"practice","title":"Practica ahora","body":"Identifica qué alimentos no aportan raciones.","exerciseId":"n5-ex2"}]'::jsonb),
('l5-lesson-3', 'nivel-5', 3, 'Casos del día a día', 'Meriendas y platos completos.', '[{"id":"l5-3-s1","type":"explanation","title":"Situaciones reales","body":"Plátano con yogur, lentejas estofadas o pasta con tomate son situaciones que encontrarás a menudo. Practica con porciones reales."},{"id":"l5-3-s2","type":"example","title":"Ejemplo: lentejas estofadas","body":"1 plato completo (300 g) puede aportar 30 g de HC = 3,0 raciones.","foodId":"lentejas-estofadas"},{"id":"l5-3-practice","type":"practice","title":"Practica ahora","body":"Resuelve un caso real de comida española.","exerciseId":"n5-ex4"}]'::jsonb)
INSERT INTO public.level_exams (level_id, title, description, exercise_ids, pool_exercise_ids, questions_per_exam) VALUES
('nivel-1', 'Examen — Nivel 1', 'Demuestra lo aprendido sobre raciones, gramos y alimentos básicos. Necesitas al menos 60% para aprobar y desbloquear el modo libre. Cada intento sortea 4 preguntas del banco del nivel.', '["n1-ex1","n1-ex2","n1-ex3","n1-ex4","n1-ex5","n1-ex6","n1-ex7","n1-ex8"]'::jsonb, '["n1-ex1","n1-ex2","n1-ex3","n1-ex4","n1-ex5","n1-ex6","n1-ex7","n1-ex8"]'::jsonb, 4),
('nivel-2', 'Examen — Nivel 2', 'Cereales y tubérculos: arroz, pasta, patata y boniato. 4 preguntas sorteadas de un banco de 8.', '["n2-ex1","n2-ex2","n2-ex3","n2-ex4","n2-ex5","n2-ex6","n2-ex7","n2-ex8"]'::jsonb, '["n2-ex1","n2-ex2","n2-ex3","n2-ex4","n2-ex5","n2-ex6","n2-ex7","n2-ex8"]'::jsonb, 4),
('nivel-3', 'Examen — Nivel 3', 'Legumbres y verduras con más contenido de carbohidratos. 4 preguntas sorteadas.', '["n3-ex1","n3-ex2","n3-ex3","n3-ex4","n3-ex5","n3-ex6","n3-ex7","n3-ex8"]'::jsonb, '["n3-ex1","n3-ex2","n3-ex3","n3-ex4","n3-ex5","n3-ex6","n3-ex7","n3-ex8"]'::jsonb, 4),
('nivel-4', 'Examen — Nivel 4', 'Platos mixtos: tortilla, bocadillo, paella y pizza. 4 preguntas sorteadas.', '["n4-ex1","n4-ex2","n4-ex3","n4-ex4","n4-ex5","n4-ex6","n4-ex7","n4-ex8"]'::jsonb, '["n4-ex1","n4-ex2","n4-ex3","n4-ex4","n4-ex5","n4-ex6","n4-ex7","n4-ex8"]'::jsonb, 4),
('nivel-5', 'Examen — Nivel 5', 'Casos reales: combinar alimentos, moduladores y comidas completas. 5 preguntas sorteadas de un banco de 10.', '["n5-ex1","n5-ex2","n5-ex3","n5-ex4","n5-ex5","n5-ex6","n5-ex7","n5-ex8","n5-ex9","n5-ex10"]'::jsonb, '["n5-ex1","n5-ex2","n5-ex3","n5-ex4","n5-ex5","n5-ex6","n5-ex7","n5-ex8","n5-ex9","n5-ex10"]'::jsonb, 5)
